diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index 1ba548b6ff06..fc52da1dd3cb 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -1153,6 +1153,7 @@ static bool MulWillOverflow(APInt &C0, APInt &C1, bool IsSigned) {
 // does not overflow.
 // Simplifies (X / C0) * C1 + (X % C0) * C2 to
 // (X / C0) * (C1 - C2 * C0) + X * C2
+
 Value *InstCombinerImpl::SimplifyAddWithRemainder(BinaryOperator &I) {
   Value *LHS = I.getOperand(0), *RHS = I.getOperand(1);
   Value *X, *MulOpV;
@@ -1180,6 +1181,35 @@ Value *InstCombinerImpl::SimplifyAddWithRemainder(BinaryOperator &I) {
     }
   }

+  // Match the unsigned power-of-two decomposition:
+  //   (X >> ShAmt) + (X & ((1 << ShAmt) - 1))
+  // and rewrite it as:
+  //   X + (X >> ShAmt) * (1 - (1 << ShAmt))
+  {
+    Value *Base = nullptr;
+    const APInt *ShAmtC = nullptr, *MaskC = nullptr;
+    auto MatchLShrAndMask = [&](Value *A, Value *B) -> bool {
+      return match(A, m_LShr(m_Value(Base), m_APInt(ShAmtC))) &&
+             match(B, m_And(m_Specific(Base), m_APInt(MaskC)));
+    };
+
+    if ((MatchLShrAndMask(LHS, RHS) || MatchLShrAndMask(RHS, LHS)) &&
+        ShAmtC && MaskC &&
+        ShAmtC->ult(Base->getType()->getScalarSizeInBits())) {
+      unsigned BitWidth = Base->getType()->getScalarSizeInBits();
+      APInt Divisor(BitWidth, 1);
+      Divisor <<= ShAmtC->getZExtValue();
+      if (*MaskC == Divisor - 1) {
+        Value *Div = match(LHS, m_LShr(m_Specific(Base), m_APInt(ShAmtC))) ? LHS
+                                                                           : RHS;
+        APInt NewC = APInt(BitWidth, 1) - Divisor;
+        Value *Mul =
+            Builder.CreateMul(Div, ConstantInt::get(Base->getType(), NewC));
+        return Builder.CreateAdd(Mul, Base);
+      }
+    }
+  }
+
   // Match I = (X / C0) * C1 + (X % C0) * C2
   Value *Div, *Rem;
   APInt C1, C2;
@@ -1210,6 +1240,7 @@ Value *InstCombinerImpl::SimplifyAddWithRemainder(BinaryOperator &I) {
   return nullptr;
 }

+
 /// Fold
 ///   (1 << NBits) - 1
 /// Into:
